class ShiftDataView(DialogView):
    title = "Shift Pattern"
    builder = resource_filename(__name__, "glade/lines/shift_dialog.glade")
    subview_builder = resource_filename(__name__, "glade/lines/shifting.glade")
    subview_toplevel = "shift_pattern"
    modal = False  # non-modal so the main plot remains interactive while the dialog is open
    resizable = False

    def __init__(self, *args, **kwargs):
        super(ShiftDataView, self).__init__(*args, **kwargs)
        if self.parent is not None:
            dialog = self.get_toplevel()
            # Keep dialog floating above the main window without blocking input
            dialog.set_transient_for(self.parent.get_toplevel())
            # set_keep_above ensures the dialog stays in front on Windows even
            # when the user clicks the main plot — without stealing focus.
            dialog.set_keep_above(True)

